import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void targetInMiddle() {
        // [1,3,5,7,9] target=5 is at index 2
        assertEquals(2, new Solution().search(new int[]{1, 3, 5, 7, 9}, 5));
    }

    @Test
    void targetNotPresent() {
        // 4 is not in the array — sentinel -1
        assertEquals(-1, new Solution().search(new int[]{1, 3, 5, 7, 9}, 4));
    }

    @Test
    void emptyArray() {
        // Empty input must return -1 without throwing
        assertEquals(-1, new Solution().search(new int[]{}, 1));
    }

    @Test
    void singleElementMatch() {
        assertEquals(0, new Solution().search(new int[]{42}, 42));
    }

    @Test
    void singleElementNoMatch() {
        assertEquals(-1, new Solution().search(new int[]{42}, 7));
    }

    @Test
    void targetAtFirstIndex() {
        assertEquals(0, new Solution().search(new int[]{2, 4, 6, 8, 10}, 2));
    }

    @Test
    void targetAtLastIndex() {
        assertEquals(4, new Solution().search(new int[]{2, 4, 6, 8, 10}, 10));
    }
}
